import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Swal from 'sweetalert2';
import Navbar from './components/Navbar';
import Katalog from './pages/Katalog';
import DetailProduk from './pages/DetailProduk';
import Keranjang from './pages/Keranjang';
import Login from './pages/Login';

function App() {
  const [kataKunci, setKataKunci] = useState('');
  const [keranjang, setKeranjang] = useState([]);

  const tambahKeKeranjang = (produk) => {
    const adaDiKeranjang = keranjang.find((item) => item.id === produk.id);

    if (adaDiKeranjang) {
      setKeranjang(
        keranjang.map((item) =>
          item.id === produk.id ? { ...adaDiKeranjang, jumlah: adaDiKeranjang.jumlah + 1 } : item
        )
      );
    } else {
      setKeranjang([...keranjang, { ...produk, jumlah: 1 }]);
    }

    // Memberikan feedback instan sesuai prinsip usability di laporan Anda
    Swal.fire({
      icon: 'success',
      title: 'Berhasil!',
      text: `${produk.nama} telah ditambahkan ke keranjang.`,
      showConfirmButton: false,
      timer: 1500,
      toast: true,
      position: 'top-end'
    });
  };

  return (
    <Router>
      <Navbar setKataKunci={setKataKunci} jumlahKeranjang={keranjang.length} />
      <Routes>
        <Route 
          path="/" 
          element={<Katalog kataKunci={kataKunci} tambahKeKeranjang={tambahKeKeranjang} />} 
        />
        <Route path="/produk/:id" element={<DetailProduk />} />
        <Route 
          path="/keranjang" 
          element={<Keranjang keranjang={keranjang} setKeranjang={setKeranjang} />} 
        />
        <Route path="/login" element={<Login />} />
      </Routes>
    </Router>
  );
}

export default App;
